import React, { useState, useEffect } from 'react';

const App = () => {
  const [menuData, setMenuData] = useState({});
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [loading, setLoading] = useState(true);
  const [selectedMensa, setSelectedMensa] = useState('all');

  const API_BASE = 'http://localhost:8000';

  useEffect(() => {
    fetch(`${API_BASE}/menu/${date}`)
      .then(res => res.json())
      .then(data => {
        const grouped = {};
        data.forEach(meal => {
          if (!grouped[meal.mensa]) grouped[meal.mensa] = [];
          grouped[meal.mensa].push(meal);
        });
        setMenuData(grouped);
        setLoading(false);
      })
      .catch(err => {
        console.error(err);
        setLoading(false);
      });
  }, [date]);

  if (loading) return <div className="p-8 text-center">Loading menu...</div>;

  const getAllMensas = () => {
    return Object.keys(menuData).sort();
  };

  const getDisplayedMensas = () => {
    const allMensas = getAllMensas();
    if (selectedMensa === 'all') return allMensas;
    return allMensas.filter(m => m === selectedMensa);
  };

  const cleanDishName = (name) => {
    // Remove allergen annotations like (3,a.1,a,f)
    return name
      .replace(/\(\d+[\s,\s]*[a-z\.]*[a-z]*\s*\)/g, '')
      .replace(/\(\d+[\s,\s]*[a-z\.]*[a-z]*\)/g, '')
      .replace(/\s*\([^)]+\)\s*$/g, '')
      .trim();
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <nav className="bg-blue-600 p-4 shadow-lg">
        <div className="max-w-6xl mx-auto">
          <h1 className="text-2xl font-bold text-white text-center">ðŸ˜‹ Canteen Food Rating</h1>
          <p className="text-center text-blue-200 text-sm mt-1">Rate meals at mensas in GÃ¶ttingen</p>
        </div>
      </nav>

      <div className="max-w-6xl mx-auto p-4">
        <div className="flex flex-wrap gap-4 mb-6 justify-center">
          <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="border p-2 rounded shadow-sm bg-white"
          />
          <select
            value={selectedMensa}
            onChange={(e) => setSelectedMensa(e.target.value)}
            className="border p-2 rounded shadow-sm bg-white"
          >
            <option value="all">All Mensas</option>
            {getAllMensas().map(mensa => (
              <option key={mensa} value={mensa}>{mensa}</option>
            ))}
          </select>
        </div>

        {Object.keys(menuData).length === 0 ? (
          <div className="text-center p-8 text-gray-500">
            <p>No menu found for this date.</p>
            <p className="text-sm mt-2">The next 7 days of menus are available.</p>
          </div>
        ) : (
          getDisplayedMensas().map(mensa => (
            <div key={mensa} className="mb-8">
              <div className="bg-blue-700 text-white px-4 py-3 rounded-t-lg font-bold text-lg">
                {mensa}
              </div>
              <div className="grid gap-4">
                {menuData[mensa]
                  .filter(m => m.type !== 'side' || m.type !== 'dessert' || m.type === 'dessert' || m.type === 'side')
                  .map(meal => (
                    <MealCard key={meal.id} meal={meal} cleanName={cleanDishName} />
                  ))
                }
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

const MealCard = ({ meal, cleanName }) => {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState('');
  const [userName, setUserName] = useState('');
  const [submitted, setSubmitted] = useState(false);

  const API_BASE = 'http://localhost:8000';

  const submitRating = async () => {
    if (rating === 0) return;
    await fetch(`${API_BASE}/rate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        meal_id: meal.id,
        rating,
        comment,
        user_name: userName,
      }),
    });
    setSubmitted(true);
  };

  const avgRating = meal._avgRating || 0;

  const getBadgeColor = (type) => {
    switch(type) {
      case 'vegan': return 'bg-green-100 text-green-800 border-green-300';
      case 'vegetarian': return 'bg-yellow-100 text-yellow-800 border-yellow-300';
      case 'dessert': return 'bg-pink-100 text-pink-800 border-pink-300';
      default: return 'bg-gray-100 text-gray-800 border-gray-300';
    }
  };

  return (
    <div className="bg-white border border-gray-200 rounded-lg shadow-sm hover:shadow-md transition-shadow">
      <div className="p-4">
        <div className="flex justify-between items-start mb-2">
          <div className="flex-1 mr-4">
            <div className="flex items-center gap-2 flex-wrap">
              <span className="text-2xl font-semibold text-gray-800">
                {cleanName(meal.name)}
              </span>
              <span className={`text-xs font-medium px-2 py-0.5 rounded border ${getBadgeColor(meal.type)}`}>
                {meal.type.toUpperCase()}
              </span>
            </div>
          </div>
        </div>

        {!submitted ? (
          <div className="mt-3 pt-3 border-t border-gray-100">
            <div className="flex gap-2 text-2xl mb-2">
              {[1, 2, 3, 4, 5].map(star => (
                <button
                  key={star}
                  onClick={() => setRating(star)}
                  className={`transition-colors hover:scale-110 ${rating >= star ? 'text-yellow-400' : 'text-gray-300'}`}
                >
                  â˜…
                </button>
              ))}
              {rating > 0 && <span className="text-sm text-gray-500 ml-2">{rating}/5</span>}
            </div>

            <input
              placeholder="Your name (optional)"
              className="w-full border p-2 rounded mb-2 text-sm"
              value={userName}
              onChange={(e) => setUserName(e.target.value)}
            />
            <textarea
              placeholder="What did you think?"
              className="w-full border p-2 rounded mb-2 text-sm"
              rows={2}
              value={comment}
              onChange={(e) => setComment(e.target.value)}
            />
            <button
              onClick={submitRating}
              className={`w-full py-2 rounded font-medium transition-colors ${rating > 0 ? 'bg-blue-600 text-white hover:bg-blue-700' : 'bg-gray-300 text-gray-500 cursor-not-allowed'}`}
            >
              Submit Rating
            </button>
          </div>
        ) : (
          <div className="mt-3 pt-3 border-t border-gray-100 text-center text-green-600 font-medium">
            Thanks for your rating!
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
